'use client';

import * as React from 'react';
import { motion } from 'framer-motion';
import { LucideIcon } from 'lucide-react';
import { cn } from '@/lib/utils';

export const fadeUpVariant = {
  hidden: { opacity: 0, y: 40 },
  show: { 
    opacity: 1, 
    y: 0, 
    transition: { 
      type: 'spring', 
      stiffness: 60, 
      damping: 20, 
      mass: 1 
    } 
  },
};

interface PageHeroProps extends React.HTMLAttributes<HTMLDivElement> {
  title: React.ReactNode;
  description?: React.ReactNode;
  icon?: LucideIcon;
  gradientFrom?: string;
  gradientPosition?: 'top' | 'center' | 'bottom_left' | 'bottom_right' | 'top_right';
  className?: string;
  children?: React.ReactNode;
}

export function PageHero({
  title,
  description,
  icon: Icon,
  gradientFrom = 'from-white/20',
  gradientPosition = 'top',
  className,
  children,
  ...props
}: PageHeroProps) {
  const gradientClass = React.useMemo(() => {
    switch (gradientPosition) {
      case 'center':
        return 'bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))]';
      case 'bottom_left':
        return 'bg-[radial-gradient(ellipse_at_bottom_left,_var(--tw-gradient-stops))]';
      case 'bottom_right':
        return 'bg-[radial-gradient(ellipse_at_bottom_right,_var(--tw-gradient-stops))]';
      case 'top_right':
        return 'bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))]';
      case 'top':
      default:
        return 'bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))]';
    }
  }, [gradientPosition]);

  return (
    <section className={cn('relative w-full overflow-hidden bg-brand pt-32 pb-20 sm:pt-40 sm:pb-32', className)} {...props}>
      <div className={cn('absolute inset-0 via-transparent to-transparent opacity-60', gradientClass, gradientFrom)}></div>
      <div className="container relative z-10 px-4 sm:px-6">
        <motion.div 
          initial="hidden"
          animate="show"
          variants={fadeUpVariant}
          className="max-w-4xl mx-auto text-center"
        >
          {Icon && (
            <div className="mx-auto mb-6 flex h-16 w-16 items-center justify-center rounded-2xl bg-white/10 backdrop-blur-md">
              <Icon className="h-8 w-8 text-white" />
            </div>
          )}
          <h1 className="font-headline text-5xl md:text-6xl lg:text-7xl font-extrabold tracking-tight text-white">
            {title}
          </h1>
          {description && (
            <p className="mt-6 text-lg sm:text-xl md:text-2xl text-white/80 max-w-3xl mx-auto leading-relaxed">
              {description}
            </p>
          )}
          {children && <div className="mt-10">{children}</div>}
        </motion.div>
      </div>
    </section>
  );
}
